func:
// === 設定 ===
//const TOKEN = 'MTQyNTEzNDU2MTUxOTQ2ODY0Ng.G4FK4g.gHDJ3LCLr_mjoQsga8nf5H8RDtwZscPWo3jbJo'
const CHANNEL_ID = '1425128928472727572'
const INTENTS = 1 /*Guilds*/ + 512 /*GuildMessages*/ + 32768 /*MessageContent*/; // = 33281
const MY_DEVICE_ID = "M5-8"; // ←このRasPiの担当IDに固定

flow.set("MY_DEVICE_ID", MY_DEVICE_ID)

// === ユーティリティ ===
function sendToWS(msgs) {
    // 1つ目の出力は WebSocket OUT へ
    node.send([].concat(msgs, [null]));
}
function forwardEvent(msg) {
    // 2つ目の出力は アプリ側へ（Debugなど）
    node.send([null, msg]);
}

// コンテキスト（接続ごとの状態）
const s = context.get('s') || null;              // 直近のシーケンス番号
let hbTimer = context.get('hbTimer') || null;    // setInterval のID
let hbInterval = context.get('hbInterval') || 0; // ms

// 受信処理
let payload;
try {
    payload = (typeof msg.payload === 'string') ? JSON.parse(msg.payload) : msg.payload;
} catch (e) {
    node.warn('JSON parse error');
    return; // 無視
}

// Discord Gateway opcode で分岐
const op = payload.op;
const t = payload.t;   // イベント名 (DISPATCH のとき)
const d = payload.d;   // データ
const seq = payload.s;   // シーケンス番号

if (seq !== undefined && seq !== null) {
    context.set('s', seq);
}

switch (op) {
    case 10: { // HELLO
        hbInterval = d.heartbeat_interval; // ms
        context.set('hbInterval', hbInterval);
        node.status({ fill: "green", shape: "dot", text: `HELLO interval=${hbInterval}ms` });

        // 既存のタイマーを止める
        if (hbTimer) { clearInterval(hbTimer); hbTimer = null; }

        // HEARTBEAT送信タイマー開始
        hbTimer = setInterval(() => {
            const sNow = context.get('s') || null;
            const hb = { op: 1, d: sNow }; // HEARTBEAT
            sendToWS({ payload: JSON.stringify(hb) });
        }, hbInterval);
        context.set('hbTimer', hbTimer);

        // IDENTIFY を送信
        if (!TOKEN) {
            node.error('DISCORD_TOKEN が設定されていません');
            return;
        }
        const identify = {
            op: 2,
            d: {
                token: `Bot ${TOKEN}`,
                intents: INTENTS,
                properties: { os: "linux", browser: "nodered", device: "nodered" }
            }
        };
        sendToWS({ payload: JSON.stringify(identify) });
        return; // ここで終了（下の共通処理は通さない）
    }
    case 11: { // HEARTBEAT ACK
        node.status({ fill: "green", shape: "ring", text: "HB ACK" });
        return;
    }
    case 9: { // INVALID SESSION
        node.status({ fill: "red", shape: "dot", text: "INVALID SESSION" });
        // 簡易: 再IDENTIFY（本来は RESUME を考慮）
        const identify = {
            op: 2,
            d: {
                token: `Bot ${TOKEN}`,
                intents: INTENTS,
                properties: { os: "linux", browser: "nodered", device: "nodered" }
            }
        };
        sendToWS({ payload: JSON.stringify(identify) });
        return;
    }
    case 7: { // RECONNECT 要求
        node.status({ fill: "yellow", shape: "dot", text: "RECONNECT requested" });
        // Node-REDのWSクライアントが自動再接続する想定。何もしない。
        return;
    }
    case 0: { // DISPATCH（イベント）
        if (t === 'READY') {
            node.status({ fill: "blue", shape: "dot", text: `READY ${d.user?.username || ''}` });
        }
        if (t === 'MESSAGE_CREATE') {
            // チャネルでフィルタ
            if (!CHANNEL_ID || d.channel_id === CHANNEL_ID) {
                forwardEvent({
                    payload: {
                        type: 'message',
                        id: d.id,
                        channel_id: d.channel_id,
                        guild_id: d.guild_id,
                        author: d.author?.username + '#' + d.author?.discriminator,
                        content: d.content || '',
                        timestamp: d.timestamp
                    }
                });
            }
        }
        return;
    }
    default:
        // そのまま生パケットを観察したい場合は下行のコメント解除
        // forwardEvent({ payload });
        return;
}

const now = Date.now();
const payload = (typeof msg.payload?.content === "string") ? msg.payload.content : msg.payload;

function fail(reason) { node.warn(reason); return null; }

msg.my_device_id = flow.get("MY_DEVICE_ID") || "m5-a"

// payload must be string
if (typeof payload !== "string") return fail("payload must be string");

// normalize newlines
const s = payload.replace(/\r\n/g, "\n");
const lines = s.split("\n");
const headerRaw = (lines[0] ?? "").trim();
const text = (lines.length >= 2) ? lines.slice(1).join("\n") : "";

// header must start with dot
if (!headerRaw.startsWith(".")) return null; // ヘッダ無しは無視（仕様）

// split tokens
const parts = headerRaw.split(".").filter(p => p.length > 0);
if (parts.length < 1) return fail("device id missing");

const device = parts[0].trim();
if (device.toUpperCase() !== msg.my_device_id.toUpperCase()) return null; // 自分宛て以外は破棄

const tokens = parts.slice(1);

// ------------------------------------------------------------
// last-wins parse
// ------------------------------------------------------------
let dStr = null;   // YYYY/MM/DD
let tStr = null;   // HH:MM:SSmsMMM / 
let dtMs = null;   // number

// move tokens (last-wins)
let xDeg = null;   // number (deg)
let yDeg = null;   // number (deg)
let mMs = null;   // number (ms)

// face / mouth (last-wins)
let face = null;   // "N"|"A"|"S"|"H"|"D"|"L"
let mouth = null;  // 0..10

for (const tokRaw of tokens) {
  const tok = String(tokRaw).trim();
  if (!tok) continue;

  // --- scheduling ---
  if (/^d\d{4}\/\d{2}\/\d{2}$/i.test(tok)) { dStr = tok.substring(1); continue; }
  if (/^t\d{1,2}:\d{1,2}:\d{1,2}(ms\d{3})?$/i.test(tok)) { tStr = tok.substring(1); continue; }


  if (/^dt\d+(\.\d+)?s$/i.test(tok)) {
    const sec = parseFloat(tok.substring(2, tok.length - 1));
    dtMs = Math.round(sec * 1000);
    continue;
  }
  if (/^dt\d+ms$/i.test(tok)) {
    dtMs = parseInt(tok.substring(2, tok.length - 2), 10);
    continue;
  }

  // --- move (last-wins) ---
  if (/^x-?\d+$/i.test(tok)) { xDeg = parseInt(tok.substring(1), 10); continue; }
  if (/^y-?\d+$/i.test(tok)) { yDeg = parseInt(tok.substring(1), 10); continue; }
  if (/^m\d+$/i.test(tok)) { mMs = parseInt(tok.substring(1), 10); continue; }

  // --- face (finalized set only: N,A,S,H,D,L) ---
  const mf = /^f([NASHDL])$/i.exec(tok);
  if (mf) { face = mf[1].toUpperCase(); continue; }

  // --- mouth size oN (0..10 clamp) ---
  const mo = /^o(-?\d+)$/i.exec(tok);
  if (mo) {
    let v = parseInt(mo[1], 10);
    if (Number.isNaN(v)) v = 0;
    if (v < 0) v = 0;
    if (v > 10) v = 10;
    mouth = v;
    continue;
  }

  // unknown tokens: ignore
}

// ------------------------------------------------------------
// validation per spec (有効条件)
// ------------------------------------------------------------
const hasText = (text.trim().length > 0);
const hasMove = (xDeg !== null) || (yDeg !== null) || (mMs !== null);
const hasFace = (face !== null);
const hasMouth = (mouth !== null);

if (!hasText && !hasMove && !hasFace && !hasMouth) {
  return fail("invalid: no text, no move, no face, no mouth");
}

// ------------------------------------------------------------
// schedule validation & compute runAtEpochMs
// ------------------------------------------------------------
const hasAbs = (tStr !== null);
const hasRel = (dtMs !== null);

if (hasAbs && hasRel) return fail("t and dt cannot coexist");
if (!hasAbs && !hasRel && dStr !== null) return fail("date-only is not allowed (t missing)");

let runAtEpochMs;
let mode;

if (!hasAbs && !hasRel) {
  mode = "asap";
  runAtEpochMs = now;
} else if (hasRel) {
  mode = "rel";
  runAtEpochMs = now + dtMs;
} else {
  mode = "abs";

  // date default = today JST
  let yyyy, MM, dd;
  if (dStr) {
    [yyyy, MM, dd] = dStr.split("/").map(v => parseInt(v, 10));
  } else {
    const jstNow = new Date(now + 9 * 3600 * 1000);
    yyyy = jstNow.getUTCFullYear();
    MM = jstNow.getUTCMonth() + 1;
    dd = jstNow.getUTCDate();
  }

  const m1 = /^(\d{1,2}):(\d{1,2}):(\d{1,2})(?:ms(\d{3}))?$/.exec(tStr);
  if (!m1) return fail("invalid t format");

  const HH = parseInt(m1[1], 10);
  const mm = parseInt(m1[2], 10);
  const SS = parseInt(m1[3], 10);
  const ms = (m1[4] !== undefined) ? parseInt(m1[4], 10) : 0;

  if (HH < 0 || HH > 23) return fail("invalid hour");
  if (mm < 0 || mm > 59) return fail("invalid minute");
  if (SS < 0 || SS > 59) return fail("invalid second");

  runAtEpochMs = Date.UTC(yyyy, MM - 1, dd, HH, mm, SS, ms) - 9 * 3600 * 1000;
}

// ------------------------------------------------------------
// wav object: ONLY when hasText
// ------------------------------------------------------------
function toJstParts(epochMs) {
  const d = new Date(epochMs + 9 * 3600 * 1000);
  const Y = d.getUTCFullYear();
  const M = String(d.getUTCMonth() + 1).padStart(2, "0");
  const D = String(d.getUTCDate()).padStart(2, "0");
  const h = String(d.getUTCHours()).padStart(2, "0");
  const m = String(d.getUTCMinutes()).padStart(2, "0");
  const s = String(d.getUTCSeconds()).padStart(2, "0");
  const ms = String(d.getUTCMilliseconds()).padStart(3, "0");
  return { Y, M, D, h, m, s, ms };
}

let wav = null;
if (hasText) {
  if (mode === "asap") {
    wav = { dir: "/home/pi/common", name: "asap.wav", name16: "asap_16.wav" };
  } else {
    const p = toJstParts(runAtEpochMs);
    wav = {
      dir: "/home/pi/common",
      name: `${p.Y}${p.M}${p.D}${p.h}${p.m}${p.s}.${p.ms}.wav`,
      name16: `${p.Y}${p.M}${p.D}${p.h}${p.m}${p.s}.${p.ms}_16.wav`
    };
  }
}

// ------------------------------------------------------------
// output normalized payload
// ------------------------------------------------------------
msg.payload = {
  device,
  text, // 本文なしなら空文字

  schedule: { mode, runAtEpochMs },

  // ★本文があるときだけ生成対象
  wav, // hasText ? {dir,name,name16} : null

  move: hasMove ? { x: xDeg, y: yDeg, m: mMs } : null,
  face: hasFace ? face : null,
  mouth: hasMouth ? mouth : null,

  meta: { receivedAtEpochMs: now, headerRaw, tokensRaw: parts }
};

return msg;

msg.url = "http://127.0.0.1:10101/audio_query"
msg.url += "?speaker=888753760"
msg.url += "&text=" + encodeURIComponent(msg.payload.text);
msg.headers = {
    "Content-Type": "application/x-www-form-urlencoded"
};

return msg;

const buf = msg.payload;
if (!Buffer.isBuffer(buf)) {
    node.error("msg.payload is not a Buffer", msg);
    return null;
}
if (buf.length < 44) {
    node.error(`WAV too short: ${buf.length} bytes`, msg);
    return null;
}
const riff = buf.toString("ascii", 0, 4);          // "RIFF"
const wave = buf.toString("ascii", 8, 12);         // "WAVE"
const fmt = buf.toString("ascii", 12, 16);        // "fmt "
const data = buf.toString("ascii", 36, 40);        // "data" (※標準44Bヘッダの場合)

const header = {
    riff,
    riffSize: buf.readUInt32LE(4),                 // fileSize-8
    wave,

    fmtChunkId: fmt,
    fmtChunkSize: buf.readUInt32LE(16),            // 通常16
    audioFormat: buf.readUInt16LE(20),             // 1=PCM
    numChannels: buf.readUInt16LE(22),
    sampleRate: buf.readUInt32LE(24),
    byteRate: buf.readUInt32LE(28),
    blockAlign: buf.readUInt16LE(32),
    bitsPerSample: buf.readUInt16LE(34),

    dataChunkId: data,
    dataSize: buf.readUInt32LE(40),

    // 参考（方式Aで使うとき便利）
    bytesPerSec: buf.readUInt32LE(24) * buf.readUInt16LE(22) * (buf.readUInt16LE(34) / 8),
    headerBytes: 44,
    dataOffset: 44
};

// PCM本体（ヘッダ44Bを除去）
msg.pcmBuffer = Buffer.from(buf.subarray(44));

// JSON化（Node-REDではオブジェクトでOK。必要なら downstream で JSON node）
msg.payload = header;

return msg;

msg.wavName = msg.payload.wav.dir + "/" + msg.payload.wav.name
msg.wavName16 = msg.payload.wav.dir + "/" + msg.payload.wav.name16
return msg;

function fail(r) { node.warn(r); return [null, { payload: { error: r } }]; }

const now = Date.now();
let q = flow.get("playQueue") || [];
let busy = flow.get("playBusy") || false;

//node.warn(q);
//node.warn(busy);

// ヘルパ
function sortQ() { q.sort((a, b) => a.runAtEpochMs - b.runAtEpochMs); }
function save() { flow.set("playQueue", q); flow.set("playBusy", busy); }

if (msg.topic === "enqueue") {
  const p = msg.payload;
  if (!p?.schedule?.runAtEpochMs || !p?.device) {
    return fail("enqueue payload invalid");
  }
  const jobId = msg.jobId || `${p.device}:${p.wav.name16}`;

  // 追加（後勝ちの重複排除をしたい場合はここで同jobIdを消す）
  // 例：同jobIdがあれば消して最後勝ち
  q = q.filter(it => it.jobId !== jobId);

  q.push({
    jobId,
    runAtEpochMs: p.schedule.runAtEpochMs,
    payload: p
  });
  sortQ();
  save();

  return [null, { payload: { enqueued: true, jobId, runAtEpochMs: p.schedule.runAtEpochMs, qlen: q.length } }];
}

// if (msg.topic === "playing") {
//   // 再生開始を知らせる（必要ならjobIdも）
//   busy = true;
//   save();
//   return [null, { payload: { playing: true, jobId: msg.jobId || null } }];
// }

// if (msg.topic === "done") {
//   busy = false;
//   save();
//   return [null, { payload: { done: true, jobId: msg.jobId || null } }];
// }

if (msg.topic === "tick") {
  if (busy) return null;         // 再生中は新規開始しない（直列再生）

  if (q.length === 0) return null;

  //node.warn(q[0].runAtEpochMs);
  //node.warn(now);

  // 期限到来判定（秒精度運用：now >= runAt で発火）
  if (q[0].runAtEpochMs > now) return null;

  const item = q.shift();
  save();

  // ここで busy を true にして「再生開始」扱いにするなら以下を有効化
  // busy = true; save();

  const out = {
    jobId: item.jobId,
    payload: item.payload
  };

  // 再生ノードへ渡す
  msg.jobId = out.jobId;
  msg.payload = out.payload;
  return [msg, { payload: { dequeued: true, jobId: out.jobId, qlen: q.length } }];
}

// 未知topicは無視
return null;

function fail(r) { node.warn(r); return null; }

const p = msg.metaData; // ← 退避している正規化payload
if (!p) return fail("metaData missing");

node.warn(p);

if (!p.device || !p.schedule?.runAtEpochMs) {
    return fail("metaData missing required fields");
}

msg.topic = "enqueue";
msg.payload = p;                 // Queueノードへ渡す実体
if (p.wav == null) {
    msg.jobId = `${p.device}:${p.schedule?.runAtEpochMs}`;
}
else {
    msg.jobId = `${p.device}:${p.wav.name16}`;
}
return msg;

//return[表情, moveXY, 音声]
let p = msg.payload;

let out0 = null;
let out1 = null;
let out2 = null;

if (p.face != null || p.mouth != null) {
    const m0 = RED.util.cloneMessage(msg);
    if (p.mouth != null) {
        m0.payload.mouth = p.mouth / 10.0
    }
    out0 = m0;
}

if (p.move != null) {
    const m1 = RED.util.cloneMessage(msg);
    const move = p?.move;
    const payload = {};
    payload.cmd = "move"
    payload.deviceId = p.device;
    if (move?.x != null) payload.x = move.x;
    if (move?.y != null) payload.y = move.y;
    if (move?.m != null) {
        payload.ms = move.m;
    }
    else {
        payload.ms = 800
    }

    if (payload?.x != null || payload?.y != null) {
        m1.payload = payload;
        out1 = m1;
    }
}

if (p.wav != null) {
    const m2 = RED.util.cloneMessage(msg);
    m2.uploadfilepath = p.wav.dir + "/" + p.wav.name16;
    out2 = m2;
}

if (out0 === null && out1 === null && out2 === null) return null;

return [out0, out1, out2];

const DEFAULT_DEVICE_ID = "m5-a";
const ROOT = "device";

msg.deviceId = msg.payload?.device;

function norm(v) {
  return String(v || "").trim().toLowerCase();
}

const faceMap = new Map([
  ["d", "doubt"],
  ["n", "neutral"],
  ["a", "angry"],
  ["s", "sleepy"],
  ["h", "happy"],
  ["l", "sad"],
]);

let deviceId =
  (typeof msg.deviceId === "string" && msg.deviceId.trim())
    ? msg.deviceId.trim()
    : DEFAULT_DEVICE_ID;

// --- ここから複数 publish 対応 ---
const out = [];


// 1) face/expr
{
  // face が無いなら何もしない
  const faceRaw = msg.payload?.face;
  const code = norm(faceRaw);
  if (code) {
    const expr = faceMap.get(code);
    if (!expr) {
      node.warn(`invalid face: ${faceRaw} (skip)`);
    } else {
      out.push({
        topic: `${ROOT}/${deviceId}/face/expr/${expr}`,
        payload: "",
        qos: Number.isFinite(msg.qos) ? msg.qos : 0,
        retain: false,
      });
      node.status({ text: `expr:${expr}` });
    }
  }
}

// 2) face/mouth / size  payload: "0.65"(0..1想定)
{
  const v = msg.payload?.mouth
  if (v !== undefined && v !== null && String(v).trim() !== "") {
    const f = Number(v);
    if (!Number.isFinite(f)) {
      node.warn(`invalid mouthSize: ${v} (skip)`);
    } else {
      // 0..1 に丸め（デバイス側でも丸めてるなら削ってOK）
      let s = f;
      if (s < 0) s = 0;
      if (s > 1) s = 1;

      out.push({
        topic: `${ROOT}/${deviceId}/face/mouth/size`,
        payload: String(s),
        qos: Number.isFinite(msg.qos) ? msg.qos : 0,
        retain: false,
      });
      node.status({ text: `mouth:${s}` });
    }
  }
}

// 何も出さないなら null
if (out.length === 0) return null;

// MQTT out へは複数メッセージを配列で返す
return [out];

// Node-RED Function node: ServoXY (topic B方式)
// Input : msg.payload = JSON object 例 {"cmd":"move","x":20,"y":-10,"ms":350}
// Output: msg.topic   = "device/<id>/servoxy/<cmd>"
//         msg.payload = "<args>" (space-separated numbers)
//
// デバイス区別しない運用でも、topicの <id> は任意文字列でOK。
// （M5側は device/+/servoxy/# を購読し、<id> は見ない設計）

const DEFAULT_DEVICE_ID = "m5-a";
const ROOT = "device";

// ranges
const X_MIN = -90, X_MAX = 90;
const Y_MIN = -90, Y_MAX = 90;
const MS_MIN = 0, MS_MAX = 60000;
const DEGSP_MIN = 0, DEGSP_MAX = 2000;

let last_x = context.get('last_x') || 0;
let last_y = context.get('last_y') || 0;



function clamp(n, lo, hi) { return Math.min(hi, Math.max(lo, n)); }
function asInt(v, name) {
  if (typeof v === "string") v = v.trim();
  const n = Number(v);
  if (!Number.isFinite(n)) throw new Error(`${name} must be number`);
  return Math.trunc(n);
}

try {
  // deviceId: msg.deviceId or msg.payload.deviceId (optional) or default
  let deviceId = null;
  if (typeof msg.deviceId === "string" && msg.deviceId.length) deviceId = msg.deviceId.trim();
  else if (msg.payload && typeof msg.payload === "object" && typeof msg.payload.deviceId === "string" && msg.payload.deviceId.length)
    deviceId = msg.payload.deviceId.trim();
  else deviceId = DEFAULT_DEVICE_ID;

  const p = msg.payload;
  if (!p || typeof p !== "object") throw new Error("payload must be JSON object");

  const cmd = String(p.cmd || p.command || "").trim().toLowerCase();
  if (!cmd) throw new Error("cmd is required");

  let payload = "";

  if (cmd === "move") {
    if (p.x == null) {
      p.x = last_x
    }
    if (p.y == null) {
      p.y = last_y
    }
    const x = clamp(asInt(p.x, "x"), X_MIN, X_MAX);
    const y = clamp(asInt(p.y, "y"), Y_MIN, Y_MAX);
    const ms = clamp(asInt(p.ms ?? p.duration, "ms"), MS_MIN, MS_MAX);
    payload = `${x} ${y} ${ms}`;
    msg.qos = Number.isFinite(msg.qos) ? msg.qos : 0;
    context.set('last_x', x)
    context.set('last_y', y)

  } else if (cmd === "stop") {
    payload = "";
    msg.qos = Number.isFinite(msg.qos) ? msg.qos : 1; // stop は QoS1 推奨

  } else if (cmd === "home") {
    const ms = clamp(asInt(p.ms ?? p.duration, "ms"), MS_MIN, MS_MAX);
    payload = `${ms}`;
    msg.qos = Number.isFinite(msg.qos) ? msg.qos : 0;

  } else if (cmd === "speed") {
    const sx = clamp(asInt(p.sx ?? p.degps_x, "sx"), DEGSP_MIN, DEGSP_MAX);
    const sy = clamp(asInt(p.sy ?? p.degps_y, "sy"), DEGSP_MIN, DEGSP_MAX);
    payload = `${sx} ${sy}`;
    msg.qos = Number.isFinite(msg.qos) ? msg.qos : 0;

  } else if (cmd === "pulse") {
    // pulseは安全のため値域チェックは入れず、整数化だけ（必要ならclamp追加）
    const minX = asInt(p.minX ?? p.min_us_x, "minX");
    const maxX = asInt(p.maxX ?? p.max_us_x, "maxX");
    const minY = asInt(p.minY ?? p.min_us_y, "minY");
    const maxY = asInt(p.maxY ?? p.max_us_y, "maxY");
    payload = `${minX} ${maxX} ${minY} ${maxY}`;
    msg.qos = Number.isFinite(msg.qos) ? msg.qos : 0;

